#include "InstCombineInternal.h"
#include "llvm/IR/PatternMatch.h"
using namespace llvm;
using namespace PatternMatch;

// Other existing code...

Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
  Value *CondVal = SI.getCondition();
  Value *TrueVal = SI.getTrueValue();
  Value *FalseVal = SI.getFalseValue();
  Type *SelType = SI.getType();

  if (Value *V = simplifySelectInst(CondVal, TrueVal, FalseVal,
                                    SQ.getWithInstruction(&SI)))
    return replaceInstUsesWith(SI, V);

  if (Instruction *I = canonicalizeSelectToShuffle(SI))
    return I;

  if (Instruction *I = canonicalizeScalarSelectOfVecs(SI, *this))
    return I;

  // Ensure correct handling of the sign of zero.
  if (auto *X = dyn_cast<ConstantFP>(TrueVal)) {
    if (auto *Y = dyn_cast<ConstantFP>(FalseVal)) {
      if (X->getType()->isFloatingPointTy() && X->isZero() && Y->isZero()) {
        return nullptr; // Skip transformation to preserve the sign of zero.
      }
    }
  }

  // Existing transformation logic...
  return nullptr;
}
EOF
